  "response_format": { "type": "json_object" },
  "messages": [
    {
      "role": "system",
      "content": "Extract structured fields from a receptionist call transcript. Return JSON only with keys: caller_name, request, details, preferred_date. Use information explicitly present in the transcript. If a field is not present, set it to \"Unknown\". Do not invent facts."
    },
    {
      "role": "user",
      "content": "Transcript:\n{{ $json.body.call_transcript || ($json.body.call && $json.body.call.transcript) || \"\" }}"
    }
  ]
}

