function isUnknown(v) {
  return !v || String(v).trim() === '' || String(v).trim().toLowerCase() === 'unknown';
}

function extractFromTranscript(text) {
  const t = String(text || '').trim();
  if (!t) {
    return {
      caller_name: 'Unknown',
      request: 'Unknown',
      details: 'Unknown',
      preferred_date: 'Unknown',
    };
  }

  const nameMatch = t.match(/(?:this is|i am|i'm|my name is)\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,2})/i);
  const dateMatch = t.match(/\b(monday|tuesday|wednesday|thursday|friday|saturday|sunday|today|tomorrow)(?:\s+at\s+\d{1,2}(?::\d{2})?\s*(?:am|pm)?)?/i)
    || t.match(/\b\d{1,2}(?::\d{2})?\s*(?:am|pm)\b/i);

  const requestSentence = t.split(/(?<=[.!?])\s+/).find((s) =>
    /\b(schedule|book|set up|appointment|follow-up|consultation|repair|estimate|call|meeting)\b/i.test(s)
  );

  return {
    caller_name: nameMatch ? nameMatch[1].trim() : 'Unknown',
    request: requestSentence ? requestSentence.trim() : t.slice(0, 180),
    details: t,
    preferred_date: dateMatch ? dateMatch[0].trim() : 'Unknown',
  };
}

const first = $input.first();
const raw = (((first || {}).json || {}).choices || [])[0]?.message?.content || '';

let cleaned = String(raw)
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let data;

try {
  data = JSON.parse(cleaned);
} catch (e) {
  data = {
    caller_name: 'Unknown',
    request: 'Unknown',
    details: cleaned || 'Unknown',
    preferred_date: 'Unknown',
  };
}

if (!data.caller_name || /john\s+doe/i.test(String(data.caller_name))) {
  data.caller_name = 'Unknown';
}

for (const key of ['caller_name', 'request', 'details', 'preferred_date']) {
  if (!data[key] || String(data[key]).trim() === '') {
    data[key] = 'Unknown';
  }
}

let transcript = '';
try {
  transcript = String($('Webhook').first().json.body.call?.transcript || $('Webhook').first().json.body.call_transcript || '');
} catch (e) {
  transcript = '';
}

if (isUnknown(data.caller_name) || isUnknown(data.request) || isUnknown(data.preferred_date)) {
  const fallback = extractFromTranscript(transcript);
  if (isUnknown(data.caller_name)) data.caller_name = fallback.caller_name;
  if (isUnknown(data.request)) data.request = fallback.request;
  if (isUnknown(data.details)) data.details = fallback.details;
  if (isUnknown(data.preferred_date)) data.preferred_date = fallback.preferred_date;
}

return [{ json: data }];

